protected void enableLineQuantityFields(
    FormDataSource                                              _agreementLineQuantityCommitment_ds,
    AgreementLineQuantityCommitmentFieldEditabilityDataProvider _dataProvider)
{
    AgreementLineQuantityCommitment     agreementLineQuantityCommitment = _agreementLineQuantityCommitment_ds.cursor();
    AgreementLineHistory                lineHistory;
    next enableLineQuantityFields(_agreementLineQuantityCommitment_ds,_dataProvider);

    select firstonly ItemId from lineHistory
        where lineHistory.AgreementLine == agreementLineQuantityCommitment.RecId;

    if(agreementLineQuantityCommitment.ETG_PriceType == ETG_PriceType::Fixed && lineHistory.ItemId)
    {
        this.setAllowEdit(_agreementLineQuantityCommitment_ds, fieldnum(AgreementLineQuantityCommitment, LineDiscountAmount), false);
        this.setAllowEdit(_agreementLineQuantityCommitment_ds, fieldnum(AgreementLineQuantityCommitment, PricePerUnit), false);
        this.setAllowEdit(_agreementLineQuantityCommitment_ds, fieldnum(AgreementLineQuantityCommitment, PriceUnit), false);       
    }
    else if(agreementLineQuantityCommitment.ETG_PriceType == ETG_PriceType::Floating)
    {
        this.setAllowEdit(_agreementLineQuantityCommitment_ds, fieldnum(AgreementLineQuantityCommitment, LineDiscountAmount), true);
        this.setAllowEdit(_agreementLineQuantityCommitment_ds, fieldnum(AgreementLineQuantityCommitment, PricePerUnit), true);
        this.setAllowEdit(_agreementLineQuantityCommitment_ds, fieldnum(AgreementLineQuantityCommitment, PriceUnit), true);
    }
}
